class Solution:
    def canIWin(self, maxChoosableInteger: int, desiredTotal: int) -> bool:
        if desiredTotal <= 0 or (maxChoosableInteger * (maxChoosableInteger + 1)) // 2 < desiredTotal:
            return True
        memo = {}
        def dfs(mask, target):
            if mask in memo:
                return memo[mask]
            for i in range(1, maxChoosableInteger + 1):
                if (mask & (1 << (i - 1))) == 0:
                    if target - i <= 0 or not dfs(mask | (1 << (i - 1)), target - i):
                        memo[mask] = True
                        return True
            memo[mask] = False
            return False
        return dfs(0, desiredTotal)
```

